:host {
  display: block;
  width: 100%;
  height: 100%;
}

.nx-value-card {
  /* Tema */
  --nx-accent: #5469FF;
  --nx-bg: #ffffff;
  --nx-border: rgba(15, 23, 42, 0.08);
  --nx-text-primary: #0f172a;
  --nx-text-secondary: #64748b;
  --nx-text-tertiary: #94a3b8;
  --nx-dot: #10b981;

  /* Tamaños adaptativos: los setea el JS, estos son fallback */
  --nx-value-size: 36px;
  --nx-label-size: 12px;
  --nx-unit-size: 16px;
  --nx-icon-box: 32px;
  --nx-icon-size: 18px;
  --nx-date-size: 11px;
  --nx-pad: 16px;
  --nx-radius: 14px;
  --nx-gap: 10px;

  position: relative;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  width: 100%;
  height: 100%;
  padding: var(--nx-pad);
  box-sizing: border-box;

  background: var(--nx-bg);
  border: 1px solid var(--nx-border);
  border-radius: var(--nx-radius);
  overflow: hidden;

  transition: border-color .2s ease, box-shadow .2s ease;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

.nx-value-card:hover {
  border-color: rgba(15, 23, 42, 0.14);
  box-shadow: 0 4px 18px rgba(15, 23, 42, 0.05);
}

.nx-vc-header {
  display: flex;
  align-items: center;
  gap: var(--nx-gap);
  min-width: 0;
}

.nx-vc-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: var(--nx-icon-box);
  height: var(--nx-icon-box);
  border-radius: 8px;
  background: color-mix(in srgb, var(--nx-accent) 14%, transparent);
  color: var(--nx-accent);
  flex-shrink: 0;
}

.nx-vc-icon tb-icon,
.nx-vc-icon mat-icon {
  font-size: var(--nx-icon-size);
  width: var(--nx-icon-size);
  height: var(--nx-icon-size);
  line-height: 1;
}

.nx-vc-label {
  font-size: var(--nx-label-size);
  font-weight: 600;
  color: var(--nx-text-secondary);
  letter-spacing: 0.04em;
  text-transform: uppercase;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  min-width: 0;
}

.nx-vc-body {
  display: flex;
  align-items: baseline;
  gap: 6px;
  flex: 1;
  margin: calc(var(--nx-pad) * 0.4) 0;
  min-width: 0;
  overflow: hidden;
}

.nx-vc-value {
  font-size: var(--nx-value-size);
  font-weight: 600;
  color: var(--nx-text-primary);
  line-height: 1;
  letter-spacing: -0.02em;
  font-variant-numeric: tabular-nums;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  min-width: 0;
}

.nx-vc-unit {
  font-size: var(--nx-unit-size);
  font-weight: 500;
  color: var(--nx-text-secondary);
  letter-spacing: -0.01em;
  white-space: nowrap;
  flex-shrink: 0;
}

.nx-vc-footer {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: var(--nx-date-size);
  color: var(--nx-text-tertiary);
  font-weight: 500;
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.nx-vc-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--nx-dot);
  flex-shrink: 0;
}

@media (prefers-color-scheme: dark) {
  .nx-value-card {
    --nx-bg: #0f172a;
    --nx-border: rgba(255, 255, 255, 0.08);
    --nx-text-primary: #f8fafc;
    --nx-text-secondary: #94a3b8;
    --nx-text-tertiary: #64748b;
  }
  .nx-value-card:hover {
    border-color: rgba(255, 255, 255, 0.14);
    box-shadow: 0 4px 18px rgba(0, 0, 0, 0.3);
  }
}

descriptor.controllerScript:
self.onInit = function() {
  var ctx = self.ctx;
  var s = ctx.settings || {};

  // Overrides de settings (los que el usuario fija a mano)
  ctx.$scope._unitsOverride    = (s.units != null && s.units !== '') ? s.units : null;
  ctx.$scope._decimalsOverride = (s.decimals != null && s.decimals !== '') ? Number(s.decimals) : null;

  // Visibilidad y estilo
  ctx.$scope.icon          = s.icon || 'analytics';
  ctx.$scope.showIcon      = s.showIcon !== false;
  ctx.$scope.showTimestamp = s.showTimestamp !== false;

  // Estado inicial
  ctx.$scope.label         = '';
  ctx.$scope.units         = '';
  ctx.$scope.valueText     = '—';
  ctx.$scope.timestampText = '';
  ctx.$scope.lastTs        = null;

  // Aplicar accent color
  var rootEl = ctx.$container && ctx.$container[0];
  var card = rootEl && rootEl.querySelector('.nx-value-card');
  if (card && s.accentColor) {
    card.style.setProperty('--nx-accent', s.accentColor);
  }

  // ResizeObserver: ajusta los tamaños según el tamaño real del card
  if (card && typeof ResizeObserver !== 'undefined') {
    self._ro = new ResizeObserver(function() { applyAdaptiveSizes(card); });
    self._ro.observe(card);
    applyAdaptiveSizes(card);
  }

  // Refresca el timestamp relativo cada 30s
  self._tickInterval = setInterval(function() {
    if (ctx.$scope.lastTs) {
      ctx.$scope.timestampText = formatRelativeTime(ctx.$scope.lastTs);
      ctx.detectChanges();
    }
  }, 30000);
};

self.onDataUpdated = function() {
  var ctx = self.ctx;
  var data = ctx.data;
  if (!data || !data.length) {
    ctx.$scope.valueText = '—';
    ctx.detectChanges();
    return;
  }

  var series = data[0];
  var dk = series.dataKey || {};

  // Label
  if (dk.label) ctx.$scope.label = dk.label;

  // Units: override de settings → unit del data key → vacío
  ctx.$scope.units = ctx.$scope._unitsOverride || dk.units || '';

  // Decimals: override de settings → decimals del data key → 1
  var decimals = ctx.$scope._decimalsOverride;
  if (decimals == null && dk.decimals != null) decimals = dk.decimals;
  if (decimals == null) decimals = 1;

  if (series.data && series.data.length) {
    var lastPoint = series.data[series.data.length - 1];
    var ts  = lastPoint[0];
    var val = lastPoint[1];

    if (val !== null && val !== undefined && val !== '') {
      var num = Number(val);
      if (!isNaN(num) && isFinite(num)) {
        ctx.$scope.valueText = num.toFixed(decimals);
      } else {
        ctx.$scope.valueText = String(val);
      }
    } else {
      ctx.$scope.valueText = '—';
    }

    ctx.$scope.lastTs = ts;
    ctx.$scope.timestampText = formatRelativeTime(ts);
  }

  ctx.detectChanges();
};

self.onResize = function() {
  // El ResizeObserver hace el grueso; este es solo un disparo extra
  var rootEl = self.ctx.$container && self.ctx.$container[0];
  var card = rootEl && rootEl.querySelector('.nx-value-card');
  if (card) applyAdaptiveSizes(card);
};

self.onDestroy = function() {
  if (self._ro) { self._ro.disconnect(); self._ro = null; }
  if (self._tickInterval) { clearInterval(self._tickInterval); self._tickInterval = null; }
};

function applyAdaptiveSizes(card) {
  var w = card.clientWidth;
  var h = card.clientHeight;
  if (!w || !h) return;

  var minDim = Math.min(w, h);

  // Breakpoints calibrados para verse bien de ~120px a ~500px
  var valueSize  = clamp(18, minDim * 0.22, 64);
  var labelSize  = clamp(10, minDim * 0.065, 14);
  var unitSize   = clamp(11, minDim * 0.09, 22);
  var iconBox    = clamp(24, minDim * 0.18, 40);
  var iconSize   = clamp(14, minDim * 0.10, 22);
  var dateSize   = clamp(10, minDim * 0.055, 12);
  var pad        = clamp(10, minDim * 0.07, 22);
  var radius     = clamp(8,  minDim * 0.05, 16);
  var gap        = clamp(6,  minDim * 0.045, 12);

  card.style.setProperty('--nx-value-size', valueSize + 'px');
  card.style.setProperty('--nx-label-size', labelSize + 'px');
  card.style.setProperty('--nx-unit-size',  unitSize  + 'px');
  card.style.setProperty('--nx-icon-box',   iconBox   + 'px');
  card.style.setProperty('--nx-icon-size',  iconSize  + 'px');
  card.style.setProperty('--nx-date-size',  dateSize  + 'px');
  card.style.setProperty('--nx-pad',        pad       + 'px');
  card.style.setProperty('--nx-radius',     radius    + 'px');
  card.style.setProperty('--nx-gap',        gap       + 'px');
}

function clamp(min, val, max) {
  return Math.max(min, Math.min(max, val));
}

function formatRelativeTime(ts) {
  if (!ts) return '';
  var diff = Math.max(0, Math.floor((Date.now() - ts) / 1000));
  if (diff < 5)     return 'justo ahora';
  if (diff < 60)    return 'hace ' + diff + ' s';
  if (diff < 3600)  return 'hace ' + Math.floor(diff / 60) + ' min';
  if (diff < 86400) return 'hace ' + Math.floor(diff / 3600) + ' h';
  return 'hace ' + Math.floor(diff / 86400) + ' d';
}

